      'svc.s1.p':    'Solutions structurales compl\u00e8tes pour la construction neuve, la r\u00e9novation et la consultation pour tous types de b\u00e2timents au Canada.',
      'svc.s2.cat':  '02 \u2014 Inspections de conformit\u00e9 OBC',
      'svc.s2.h2':   'Conformit\u00e9 au code<br>canadien',
      'svc.s2.p':    "Inspections certifi\u00e9es de l\u2019enveloppe des b\u00e2timents, des parcs de stationnement et des trottoirs avec dossiers complets de permis \u2014 b\u00e2timent conforme et occupants en s\u00e9curit\u00e9.",
      'svc.s3.cat':  '03 \u2014 Ing\u00e9nierie des ouvrages temporaires',
      'svc.s3.h2':   'Ouvrages temporaires<br>et s\u00e9curit\u00e9 du chantier',
      'svc.s3.p':    "Ing\u00e9nierie d\u00e9taill\u00e9e pour chaque phase de construction \u2014 du phasage d\u2019\u00e9rection \u00e0 la conception de batardeaux et \u00e0 la protection a\u00e9rienne.",
      'svc.s4.cat':  '04 \u2014 Ing\u00e9nierie sp\u00e9cialis\u00e9e',
      'svc.s4.h2':   'Ing\u00e9nierie sp\u00e9cialis\u00e9e<br>et de d\u00e9tail',
      'svc.s4.p':    'Solutions cibl\u00e9es pour les syst\u00e8mes de toiture, connexions structurales et coffrages \u2014 conformes CCO/CNB et con\u00e7us pour la performance.',

      'svc.01.li': '<li>Remplacement de poutres et colonnes</li><li>Encadrement d\u2019ouvertures et ajouts</li><li>R\u00e9habilitation de ma\u00e7onnerie</li><li>R\u00e9paration d\u2019acier et de b\u00e9ton</li>',
      'svc.02.li': '<li>Dossiers structuraux pour construction neuve</li><li>Conception de charpente acier et b\u00e9ton</li><li>Structures en bois et ma\u00e7onnerie</li><li>Plans pr\u00eats pour permis de construction</li>',
      'svc.03.li': '<li>R\u00e9vision par les pairs et contr\u00f4le tiers</li><li>Supervision de construction</li><li>Inspections sp\u00e9ciales et de suivi</li><li>\u00c9valuation des dommages et de l\u2019\u00e9tat</li>',
      'svc.04.li': '<li>\u00c9valuations p\u00e9riodiques de l\u2019\u00e9tat</li><li>Rapports sur les conditions dangereuses</li><li>Port\u00e9e des r\u00e9parations et surveillance</li><li>D\u00e9p\u00f4t de permis et approbation</li>',
      'svc.05.li': '<li>Relev\u00e9s p\u00e9riodiques de l\u2019\u00e9tat</li><li>\u00c9valuation de l\u2019int\u00e9grit\u00e9 structurale</li><li>Rapports de priorit\u00e9 des r\u00e9parations</li><li>D\u00e9p\u00f4t de permis et conformit\u00e9</li>',
      'svc.06.li': '<li>\u00c9valuation des vo\u00fbtes et dalles</li><li>Conception et dessins de r\u00e9paration</li><li>Coordination des entrepreneurs</li><li>Approbation et documentation</li>',
      'svc.07.li': '<li>S\u00e9quences de phasage d\u2019\u00e9rection</li><li>Structures de sout\u00e8nement temporaire</li><li>Plans de levage et d\u2019apparaux</li><li>Analyse des charges de construction</li>',
      'svc.08.li': '<li>Conception structurale de batardeaux</li><li>Plans d\u2019ass\u00e8chement</li><li>D\u00e9rivation de cours d\u2019eau</li><li>Surveillance de l\u2019installation</li>',
      'svc.09.li': '<li>Rapports de m\u00e9thodologie de d\u00e9molition</li><li>Plans de s\u00e9quence et de phasage</li><li>Protection environnementale</li><li>Gestion de la circulation et du chantier</li>',
      'svc.10.li': '<li>Tins de toiture et support d\u2019\u00e9quipements</li><li>R\u00e9paration de parapets et cloisons</li><li>Conception de garde-corps de s\u00e9curit\u00e9</li><li>Coordination de l\u2019imp\u00e9rm\u00e9abilisation</li>',
      'svc.11.li': '<li>Conception d\u2019ancrages post-install\u00e9s</li><li>D\u00e9tails de connexions en acier</li><li>Syst\u00e8mes d\u2019ancrage en ma\u00e7onnerie</li><li>V\u00e9rifications sismiques et de charge au vent</li>',
      'svc.12.li': '<li>Conception d\u2019\u00e9taiement de dalles et poutres</li><li>Ing\u00e9nierie des abris de trottoirs</li><li>Syst\u00e8mes de protection a\u00e9rienne</li><li>Calculs de charges et d\u00e9formations</li>',

      /* Section 05 — Ingénierie judiciaire */
      'svc.s5.cat':  '05 \u2014 Ing\u00e9nierie judiciaire',
      'svc.s5.h2':   'Analyse judiciaire<br>et des d\u00e9faillances',
      'svc.s5.p':    'Enqu\u00eate scientifique sur les d\u00e9faillances, dommages et d\u00e9fauts structuraux \u2014 livrant des conclusions d\u2019expert pour les litiges, assurances et rem\u00e9diations.',
      'svc.13.h':  'Enqu\u00eate structurale judiciaire',
      'svc.13.p':  'Enqu\u00eate sur site des d\u00e9tresses structurales, effondrements ou mouvements impr\u00e9vus pour en d\u00e9terminer la cause profonde.',
      'svc.13.li': '<li>Relev\u00e9 de site et documentation de l\u2019\u00e9tat</li><li>Coordination des pr\u00e9l\u00e8vements et essais de mat\u00e9riaux</li><li>Analyse des causes et rapport</li><li>Recommandations de rem\u00e9diation</li>',
      'svc.14.h':  'Analyse des d\u00e9faillances et rapports d\u2019experts',
      'svc.14.p':  'Analyse technique d\u00e9taill\u00e9e des d\u00e9faillances structurales pour r\u00e9clamations d\u2019assurance, proc\u00e9dures judiciaires et litiges de conformit\u00e9.',
      'svc.14.li': '<li>Examen du chemin de charge et de la capacit\u00e9</li><li>Analyse de la conformit\u00e9 aux codes</li><li>Rapports techniques pour litiges</li><li>Analyse de la chronologie et des causes</li>',
      'svc.15.h':  'T\u00e9moin expert et t\u00e9moignage',
      'svc.15.p':  'Services de t\u00e9moignage professionnel en ing\u00e9nierie pour les litiges de construction et les proc\u00e9dures d\u2019arbitrage.',
      'svc.15.li': '<li>D\u00e9position et t\u00e9moignage en tribunal</li><li>Examen par les pairs des rapports adverses</li><li>Analyse des d\u00e9fauts de construction</li><li>Soutien \u00e0 la m\u00e9diation</li>',

      /* Section 06 — Services de construction */
      'svc.s6.cat':  '06 \u2014 Services de construction',
      'svc.s6.h2':   'Gestion et conseil<br>en construction',
      'svc.s6.p':    'Services de pr\u00e9-construction et de livraison pour maintenir votre projet dans les d\u00e9lais, le budget et la coordination compl\u00e8te.',
      'svc.16.h':  'Estimation des co\u00fbts',
      'svc.16.p':  'M\u00e9tr\u00e9s pr\u00e9cis et projections de co\u00fbts pour les lots structuraux, aidant propri\u00e9taires et entrepreneurs \u00e0 budg\u00e9ter avec confiance.',
      'svc.16.li': '<li>Estimations pr\u00e9liminaires et d\u00e9taill\u00e9es</li><li>M\u00e9tr\u00e9 et tarification des mat\u00e9riaux</li><li>D\u00e9composition des co\u00fbts par lot</li><li>Examen d\u2019ing\u00e9nierie de la valeur</li>',
      'svc.17.h':  'Planification du projet',
      'svc.17.p':  'Calendriers de construction complets et analyse du chemin critique pour maintenir les projets structuraux complexes sur la bonne voie de d\u00e9but \u00e0 fin.',
      'svc.17.li': '<li>Planification par chemin critique (CPM)</li><li>Plans d\u2019\u00e9tapes et de phasage</li><li>Analyse des retards de calendrier</li><li>Planification des ressources et approvisionnements</li>',
      'svc.18.h':  'Administration de la construction',
      'svc.18.p':  'Surveillance d\u2019ing\u00e9nierie sur site et examen des dessins d\u2019atelier tout au long de la phase de construction pour assurer la conformit\u00e9 structurale.',
      'svc.18.li': '<li>Examen des dessins d\u2019atelier et soumissions</li><li>Visites de site et inspections de progression</li><li>Coordination des DI et ordres de changement</li><li>Soutien \u00e0 la documentation as-built</li>',

      'svc.why.pill':    'Pourquoi nous choisir',
      'svc.why.cta.btn': 'D\u00e9marrer votre projet \u2192',
