      /* ─── TW: Travaux provisoires en Ontario ─────────────────── */
      'art.tw.hero.pill':  'Travaux provisoires',
      'art.tw.hero.h1':    'Ingénierie des travaux provisoires en Ontario : Règl. 213/91 LSST, coffrages et étaiements',
      'art.tw.hero.p':     'Exigences du Règlement 213/91 de la LSST pour les coffrages, étaiements, cintres et soutènements d\'excavation — ce que les entrepreneurs et propriétaires de projets ontariens doivent savoir sur les travaux provisoires exigeant un ingénieur.',
      'art.tw.meta.pill':  'Travaux provisoires',
      'art.tw.meta.rt':    '7 min de lecture',
      'art.tw.toc.1':      'Que sont les travaux provisoires?',
      'art.tw.toc.2':      'Exigences du Règl. 213/91 LSST',
      'art.tw.toc.3':      'Types de travaux provisoires',
      'art.tw.toc.4':      'Exigences de conception technique',
